                <option value="price_desc">Price: High to Low</option>
                <option value="name_asc">Name: A-Z</option>
                <option value="rating_desc">Rating: Highest</option>
            </select>
        </div>

        @if (Result is not null && Result.TotalCount > 0)
        {
            var first = (Result.Page - 1) * Result.PageSize + 1;
            var last = Math.Min(Result.Page * Result.PageSize, Result.TotalCount);
            <span class="text-muted">Showing @first–@last of @Result.TotalCount products</span>
        }
    </div>

    @* Loading state *@
    @if (Loading)
    {
        <div class="text-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
            <p class="mt-2 text-muted">Loading products…</p>
        </div>
    }
    else if (ErrorMessage is not null)
    {
        <div class="alert alert-danger" role="alert">
            <strong>Error:</strong> @ErrorMessage
        </div>
    }
    else if (Result is null || Result.Items.Count == 0)
    {
        <div class="text-center py-5">
            <p class="text-muted fs-5">No products found matching your criteria.</p>
        </div>
    }
    else
    {
        @* Product card grid *@
        <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
            @foreach (var product in Result.Items)
            {
                <div class="col">
                    <ProductCard Product="product"
                                 OnSelected="OnProductSelected"
                                 OnAddToCart="OnAddToCart" />
                </div>
