                <span>@(i <= RoundedRating ? "★" : "☆")</span>
            }
        </div>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private int RoundedRating => (int)Math.Round(Product.Rating);

    private async Task HandleCardClick()
    {
        await OnSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }
}

@* Product grid with toolbar (sort + count), card grid, and pagination *@

<div>
    @* Toolbar *@
    <div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
        <div class="d-flex align-items-center gap-2">
            <label for="sort-select" class="form-label mb-0 fw-semibold">Sort by:</label>
            <select id="sort-select"
                    class="form-select form-select-sm"
                    style="width: auto;"
                    value="@SortBy"
                    @onchange="HandleSortChanged">
                <option value="price_asc">Price: Low to High</option>
                <option value="price_desc">Price: High to Low</option>
                <option value="name_asc">Name: A-Z</option>
                <option value="rating_desc">Rating: Highest</option>
            </select>
        </div>

        @if (Result is not null && Result.TotalCount > 0)
        {
            var first = (Result.Page - 1) * Result.PageSize + 1;
            var last = Math.Min(Result.Page * Result.PageSize, Result.TotalCount);
            <span class="text-muted">Showing @first–@last of @Result.TotalCount products</span>
        }
    </div>

    @* Loading state *@
    @if (Loading)
    {
        <div class="text-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
            <p class="mt-2 text-muted">Loading products…</p>
        </div>
    }
    else if (ErrorMessage is not null)
    {
        <div class="alert alert-danger" role="alert">
            <strong>Error:</strong> @ErrorMessage
        </div>
    }
    else if (Result is null || Result.Items.Count == 0)
    {
        <div class="text-center py-5">
            <p class="text-muted fs-5">No products found matching your criteria.</p>
        </div>
    }
    else
    {
        @* Product card grid *@
        <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
            @foreach (var product in Result.Items)
            {
                <div class="col">
                    <ProductCard Product="product"
                                 OnSelected="OnProductSelected"
                                 OnAddToCart="OnAddToCart" />
                </div>
            }
        </div>

        @* Pagination *@
        @if (TotalPages > 1)
        {
            <nav aria-label="Product pagination" class="mt-4">
                <ul class="pagination justify-content-center">
                    <li class="page-item @(Result.Page <= 1 ? "disabled" : "")">
                        <button class="page-link" @onclick="() => ChangePage(Result.Page - 1)">Previous</button>
                    </li>
                    @for (int i = 1; i <= TotalPages; i++)
                    {
                        var pageNum = i;
                        <li class="page-item @(pageNum == Result.Page ? "active" : "")">
                            <button class="page-link" @onclick="() => ChangePage(pageNum)">@pageNum</button>
                        </li>
                    }
                    <li class="page-item @(Result.Page >= TotalPages ? "disabled" : "")">
                        <button class="page-link" @onclick="() => ChangePage(Result.Page + 1)">Next</button>
                    </li>
                </ul>
            </nav>
        }
    }
</div>

@code {
    [Parameter]
    public PagedResult<Product>? Result { get; set; }

    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public bool Loading { get; set; }

    [Parameter]
    public string? ErrorMessage { get; set; }

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private int TotalPages =>
        Result is not null && Result.PageSize > 0
            ? (int)Math.Ceiling((double)Result.TotalCount / Result.PageSize)
            : 0;

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }

    private async Task ChangePage(int page)
    {
        if (page >= 1 && page <= TotalPages)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}

@* Filter sidebar: category checkboxes, price range, in-stock toggle, apply/clear buttons *@

<div class="p-3 border rounded bg-white">
    <h5 class="mb-3">Filters</h5>

    @* Categories *@
    <div class="mb-3">
        <label class="form-label fw-semibold">Categories</label>
        @if (Categories is null || Categories.Count == 0)
        {
            <p class="text-muted small">No categories available</p>
        }
        else
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input"
                           type="checkbox"
                           id="@($"cat-{category}")"
                           checked="@selectedCategories.Contains(category)"
                           @onchange="e => ToggleCategory(category, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    @* Price range *@
    <div class="mb-3">
        <label class="form-label fw-semibold">Price Range</label>
        <div class="d-flex gap-2 align-items-center">
            <input type="number"
                   class="form-control form-control-sm"
                   placeholder="Min"
                   min="0"
                   step="0.01"
                   @bind="minPrice" />
            <span>–</span>
            <input type="number"
                   class="form-control form-control-sm"
                   placeholder="Max"
                   min="0"
                   step="0.01"
                   @bind="maxPrice" />
        </div>
    </div>

    @* In stock toggle *@
    <div class="form-check mb-3">
        <input class="form-check-input"
               type="checkbox"
               id="in-stock-toggle"
               @bind="inStockOnly" />
        <label class="form-check-label" for="in-stock-toggle">In Stock Only</label>
    </div>

    @* Action buttons *@
    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter]
    public List<string>? Categories { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    [Parameter]
    public EventCallback OnFilterCleared { get; set; }

    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        await OnFilterCleared.InvokeAsync();
    }
}

@page "/catalog"
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-4">Product Catalog</h3>

<div class="row">
    @* Left sidebar — filters *@
    <div class="col-md-3">
        <CatalogSidebar Categories="categories"
                        OnFilterApplied="HandleFilterApplied"
                        OnFilterCleared="HandleFilterCleared" />
    </div>

    @* Main content — product grid *@
    <div class="col-md-9">
        <ProductGrid Result="result"
                     SortBy="@sortBy"
                     Loading="loading"
                     ErrorMessage="@errorMessage"
                     OnSortChanged="HandleSortChanged"
                     OnPageChanged="HandlePageChanged"
                     OnProductSelected="HandleProductSelected"
                     OnAddToCart="HandleAddToCart" />
    </div>
</div>

@code {
    private List<string>? categories;
    private PagedResult<Product>? result;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 9;
    private bool loading = true;
    private string? errorMessage;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
            await Task.WhenAll(categoriesTask, searchTask);

            categories = categoriesTask.Result;
            result = searchTask.Result;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load catalog: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private async Task SearchAsync()
    {
        loading = true;
        errorMessage = null;

        try
        {
            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Search failed: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleFilterCleared()
    {
        currentFilter = new ProductFilter(null, null, null, false);
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder — wire to a cart service when available
        return Task.CompletedTask;
    }
}

